import type { SVGSymbolProps } from "@/types/svg";
import { Gradient } from "../Gradient";
import { useVariantFill } from "@/hooks/useVariantFill";

export default function Cup ({
  size = 80,
  fill,
  animate,
  style,
  variant,
}: SVGSymbolProps) {
  const variantFill = useVariantFill(variant ?? "primary") ?? "#000";
  const cupSVG: string = "data:image/svg+xml;base64,"
  fill = fill ?? variantFill;
  const id = `${Math.random().toString(16).slice(2)}`;
  const center = size / 2;
  const scale = size / 130;
  const translateValue = 22;
  const circleRadius = (size - 2) / 2;
  return (
    <svg
        width={size}
        height={size}
        viewBox={`0 0 ${size} ${size}`}
        xmlns="http://www.w3.org/2000/svg"
        style={style}
    >
      <defs>
        {typeof fill === "object" && (
          <Gradient id={`gradient-${id}`} {...fill} />
        )}
      </defs>

      {/* Circle background */}
      <circle
        cx={center}
        cy={center}
        r={circleRadius}
        fill={typeof fill === "object" ? `url(#gradient-${id})` : fill}
      />

      <image
        href={cupSVG}
        x={5}
        y={5}
        width={size * .7}
        height={size * .7}
      />
    </svg>  
  )
};